app = Flask(__name__)

REDIS_HOST = "localhost"
REDIS_PORT = 6379
SESSION_COOKIE_NAME = "session_id"
SESSION_TTL_SECONDS = 60 * 60 * 24 * 7
CACHE_DEFAULT_TTL_SECONDS = 60

redis_client = redis.Redis(host=REDIS_HOST, port=REDIS_PORT, decode_responses=True)


def redis_available():
    try:
        redis_client.ping()
        return True
    except redis.RedisError:
        return False


def session_key(session_id):
    return f"session:{session_id}"


def cache_key(prefix, *args, **kwargs):
    payload = {
        "prefix": prefix,
        "args": args,
        "kwargs": kwargs,
    }
    raw = json.dumps(payload, sort_keys=True, default=str)
    digest = hashlib.sha256(raw.encode("utf-8")).hexdigest()
    return f"cache:{prefix}:{digest}"


def get_session_data(session_id):
    if not session_id:
        return {}
    try:
        raw = redis_client.get(session_key(session_id))
        if not raw:
            return {}
        return json.loads(raw)
    except (redis.RedisError, json.JSONDecodeError):
        return {}


def save_session_data(session_id, data, ttl=SESSION_TTL_SECONDS):
    try:
        redis_client.set(session_key(session_id), json.dumps(data), ex=ttl)
        return True
    except redis.RedisError:
        return False


def create_session(initial_data=None):
    sid = str(uuid.uuid4())
    data = initial_data or {}
    save_session_data(sid, data)
    return sid, data


def cached(ttl=CACHE_DEFAULT_TTL_SECONDS, prefix=None):
    def decorator(func):
        cache_prefix = prefix or func.__name__

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            key = cache_key(cache_prefix, *args, **kwargs)
            try:
                cached_value = redis_client.get(key)
                if cached_value is not None:
                    return json.loads(cached_value)
            except (redis.RedisError, json.JSONDecodeError):
                pass

            result = func(*args, **kwargs)

            try:
                redis_client.set(key, json.dumps(result, default=str), ex=ttl)
            except redis.RedisError:
                pass

            return result

        return wrapper

    return decorator


