@app.before_request
def load_session():
    sid = request.cookies.get(SESSION_COOKIE_NAME)
    if sid:
        g.session_id = sid
        g.session = get_session_data(sid)
        if not g.session:
            g.session_id, g.session = create_session()
    else:
        g.session_id, g.session = create_session()


@app.after_request
def persist_session(response):
    if hasattr(g, "session_id") and hasattr(g, "session"):
        save_session_data(g.session_id, g.session)
        response.set_cookie(
            SESSION_COOKIE_NAME,
            g.session_id,
            max_age=SESSION_TTL_SECONDS,
            httponly=True,
            samesite="Lax",
        )
    return response


