@app.route("/login", methods=["POST"])
def login():
    payload = request.get_json(silent=True) or {}
    username = payload.get("username") or request.form.get("username")
    if not username:
        return jsonify({"error": "username is required"}), 400

    g.session["authenticated"] = True
    g.session["username"] = username
    g.session["login_at"] = int(time.time())

    return jsonify(
        {
            "message": "logged in",
            "session_id": g.session_id,
            "session": g.session,
        }
    )


@app.route("/logout", methods=["POST"])
def logout():
    try:
        redis_client.delete(session_key(g.session_id))
    except redis.RedisError:
        pass

    g.session_id, g.session = create_session()
    response = jsonify({"message": "logged out"})
    response.set_cookie(
        SESSION_COOKIE_NAME,
        g.session_id,
        max_age=SESSION_TTL_SECONDS,
        httponly=True,
        samesite="Lax",
    )
    return response


